 962 // Public so this can be used in `SimplifyDemandedUseBits`.
 963 KnownBits llvm::analyzeKnownBitsFromAndXorOr(const Operator *I,
 964                                              const KnownBits &KnownLHS,
 965                                              const KnownBits &KnownRHS,
 966                                              unsigned Depth,
 967                                              const SimplifyQuery &SQ) {
 968   auto *FVTy = dyn_cast<FixedVectorType>(I->getType());
 969   APInt DemandedElts =
 970       FVTy ? APInt::getAllOnes(FVTy->getNumElements()) : APInt(1, 1);
 971 
 972   return getKnownBitsFromAndXorOr(I, DemandedElts, KnownLHS, KnownRHS, Depth,
 973                                   SQ);
 974 }
