 976 ConstantRange llvm::getVScaleRange(const Function *F, unsigned BitWidth) {
 977   Attribute Attr = F->getFnAttribute(Attribute::VScaleRange);
 978   // Without vscale_range, we only know that vscale is non-zero.
 979   if (!Attr.isValid())
 980     return ConstantRange(APInt(BitWidth, 1), APInt::getZero(BitWidth));
 981 
 982   unsigned AttrMin = Attr.getVScaleRangeMin();
 983   // Minimum is larger than vscale width, result is always poison.
 984   if ((unsigned)llvm::bit_width(AttrMin) > BitWidth)
 985     return ConstantRange::getEmpty(BitWidth);
 986 
 987   APInt Min(BitWidth, AttrMin);
 988   std::optional<unsigned> AttrMax = Attr.getVScaleRangeMax();
 989   if (!AttrMax || (unsigned)llvm::bit_width(*AttrMax) > BitWidth)
 990     return ConstantRange(Min, APInt::getZero(BitWidth));
 991 
 992   return ConstantRange(Min, APInt(BitWidth, *AttrMax) + 1);
 993 }
