 995 static void computeKnownBitsFromOperator(const Operator *I,
 996                                          const APInt &DemandedElts,
 997                                          KnownBits &Known, unsigned Depth,
 998                                          const SimplifyQuery &Q) {
 999   unsigned BitWidth = Known.getBitWidth();
1000 
1001   KnownBits Known2(BitWidth);
1002   switch (I->getOpcode()) {
1003   default: break;
1004   case Instruction::Load:
1005     if (MDNode *MD =
1006             Q.IIQ.getMetadata(cast<LoadInst>(I), LLVMContext::MD_range))
1007       computeKnownBitsFromRangeMetadata(*MD, Known);
1008     break;
1009   case Instruction::And:
1010     computeKnownBits(I->getOperand(1), DemandedElts, Known, Depth + 1, Q);
1011     computeKnownBits(I->getOperand(0), DemandedElts, Known2, Depth + 1, Q);
1012 
1013     Known = getKnownBitsFromAndXorOr(I, DemandedElts, Known2, Known, Depth, Q);
1014     break;
1015   case Instruction::Or:
1016     computeKnownBits(I->getOperand(1), DemandedElts, Known, Depth + 1, Q);
1017     computeKnownBits(I->getOperand(0), DemandedElts, Known2, Depth + 1, Q);
1018 
1019     Known = getKnownBitsFromAndXorOr(I, DemandedElts, Known2, Known, Depth, Q);
