 772 void llvm::computeKnownBitsFromContext(const Value *V, KnownBits &Known,
 773                                        unsigned Depth, const SimplifyQuery &Q) {
 774   // Handle injected condition.
 775   if (Q.CC && Q.CC->AffectedValues.contains(V))
 776     computeKnownBitsFromCond(V, Q.CC->Cond, Known, Depth, Q, Q.CC->Invert);
 777 
 778   if (!Q.CxtI)
 779     return;
 780 
 781   if (Q.DC && Q.DT) {
 782     // Handle dominating conditions.
 783     for (BranchInst *BI : Q.DC->conditionsFor(V)) {
 784       BasicBlockEdge Edge0(BI->getParent(), BI->getSuccessor(0));
 785       if (Q.DT->dominates(Edge0, Q.CxtI->getParent()))
 786         computeKnownBitsFromCond(V, BI->getCondition(), Known, Depth, Q,
 787                                  /*Invert*/ false);
 788 
 789       BasicBlockEdge Edge1(BI->getParent(), BI->getSuccessor(1));
 790       if (Q.DT->dominates(Edge1, Q.CxtI->getParent()))
 791         computeKnownBitsFromCond(V, BI->getCondition(), Known, Depth, Q,
 792                                  /*Invert*/ true);
 793     }
 794 
 795     if (Known.hasConflict())
 796       Known.resetAll();
 797   }
 798 
 799   if (!Q.AC)
 800     return;
 801 
 802   unsigned BitWidth = Known.getBitWidth();
 803 
 804   // Note that the patterns below need to be kept in sync with the code
 805   // in AssumptionCache::updateAffectedValues.
 806 
 807   for (AssumptionCache::ResultElem &Elem : Q.AC->assumptionsFor(V)) {
 808     if (!Elem.Assume)
 809       continue;
 810 
 811     AssumeInst *I = cast<AssumeInst>(Elem.Assume);
 812     assert(I->getParent()->getParent() == Q.CxtI->getParent()->getParent() &&
 813            "Got assumption for the wrong function!");
 814 
 815     if (Elem.Index != AssumptionCache::ExprResultIdx) {
 816       if (!V->getType()->isPointerTy())
 817         continue;
 818       if (RetainedKnowledge RK = getKnowledgeFromBundle(
 819               *I, I->bundle_op_info_begin()[Elem.Index])) {
 820         if (RK.WasOn == V && RK.AttrKind == Attribute::Alignment &&
 821             isPowerOf2_64(RK.ArgValue) &&
 822             isValidAssumeForContext(I, Q.CxtI, Q.DT))
 823           Known.Zero.setLowBits(Log2_64(RK.ArgValue));
 824       }
 825       continue;
 826     }
 827 
 828     // Warning: This loop can end up being somewhat performance sensitive.
 829     // We're running this loop for once for each value queried resulting in a
 830     // runtime of ~O(#assumes * #values).
 831 
 832     Value *Arg = I->getArgOperand(0);
 833 
 834     if (Arg == V && isValidAssumeForContext(I, Q.CxtI, Q.DT)) {
 835       assert(BitWidth == 1 && "assume operand is not i1?");
 836       (void)BitWidth;
 837       Known.setAllOnes();
 838       return;
 839     }
 840     if (match(Arg, m_Not(m_Specific(V))) &&
 841         isValidAssumeForContext(I, Q.CxtI, Q.DT)) {
 842       assert(BitWidth == 1 && "assume operand is not i1?");
 843       (void)BitWidth;
 844       Known.setAllZero();
 845       return;
 846     }
 847 
 848     // The remaining tests are all recursive, so bail out if we hit the limit.
 849     if (Depth == MaxAnalysisRecursionDepth)
 850       continue;
 851 
 852     ICmpInst *Cmp = dyn_cast<ICmpInst>(Arg);
 853     if (!Cmp)
 854       continue;
 855 
 856     if (!isValidAssumeForContext(I, Q.CxtI, Q.DT))
 857       continue;
 858 
 859     computeKnownBitsFromICmpCond(V, Cmp, Known, Q, /*Invert=*/false);
 860   }
 861 
 862   // Conflicting assumption: Undefined behavior will occur on this execution
 863   // path.
 864   if (Known.hasConflict())
 865     Known.resetAll();
 866 }
